export default function settle(resolve, reject, response) {
  const validateStatus = response.config.validateStatus;
  if (!response.status || !validateStatus || validateStatus(response.status)) {
    resolve(response);
  } else {
    reject(new AxiosError(
      'Request failed with status code ' + response.status,
      response.status >= 400 && response.status < 500 ? AxiosError.ERR_BAD_REQUEST : AxiosError.ERR_BAD_RESPONSE,
      response.config,
      response.request,
      response
    ));
  }
}

static from(error, code, config, request, response, customProps) {
  const axiosError = new AxiosError(error.message, code || error.code, config, request, response);
  axiosError.cause = error;
  axiosError.name = error.name;

  // Preserve status from the original error if not already set from response
  if (error.status != null && axiosError.status == null) {
    axiosError.status = error.status;
  }

  customProps && Object.assign(axiosError, customProps);
  return axiosError;
}

export const addChild = (parent, child, sortMethod, prevProp = '_prev', nextProp = '_next') => {
  let prev = parent._tail;
  while (prev && sortMethod && sortMethod(prev, child)) prev = prev[prevProp];
  const next = prev ? prev[nextProp] : parent._head;
  prev ? prev[nextProp] = child : parent._head = child;
  next ? next[prevProp] = child : parent._tail = child;
  child[prevProp] = prev;
  child[nextProp] = next;
}

get fps() {
  return this._fps;
}

set fps(frameRate) {
  const previousFrameDuration = this._frameDuration;
  const fr = +frameRate;
  const fps = fr < minValue ? minValue : fr;
  const frameDuration = K / fps;
  if (fps > defaults.frameRate) defaults.frameRate = fps;
  this._fps = fps;
  this._frameDuration = frameDuration;
  this._scheduledTime += frameDuration - previousFrameDuration;
}

if (this.#aborted) {
        chunks = null;
        return; // Ignoring any data after abort.
      }
      if (done) {
        break;
      }
      if (typeof PDFJSDev === "undefined" || PDFJSDev.test("TESTING")) {
        assert(
          value instanceof ArrayBuffer,
          "sendRequest - expected an ArrayBuffer."
        );
      }
      chunks.push(value);

export default function updateSlidesOffset() {
  const swiper = this;
  const slides = swiper.slides;
  // eslint-disable-next-line
  const minusOffset = swiper.isElement
    ? swiper.isHorizontal()
      ? swiper.wrapperEl.offsetLeft
      : swiper.wrapperEl.offsetTop
    : 0;
  for (let i = 0; i < slides.length; i += 1) {
    slides[i].swiperSlideOffset =
      (swiper.isHorizontal() ? slides[i].offsetLeft : slides[i].offsetTop) -
      minusOffset -
      swiper.cssOverflowAdjustment();
  }
}

const isRequireEsmModuleExportsModule = (importedModule, moduleGraph) => {
	if (importedModule.getExportsType(moduleGraph, false) !== "namespace") {
		return false;
	}
	const exportsInfo = moduleGraph.getExportsInfo(importedModule);
	const exportInfo = exportsInfo.getReadOnlyExportInfo(ESM_MODULE_EXPORTS_NAME);
	return exportInfo.provided === true;
};

if (this.tok.type.keyword || this.toks.isLet() || this.toks.isAsyncFunction()) {
  node.declaration = this.parseStatement()
  node.specifiers = []
  node.source = null
} else {
  node.declaration = null
  node.specifiers = this.parseExportSpecifierList()
  node.source = this.eatContextual("from") ? this.parseExprAtom() : null
  if (this.options.ecmaVersion >= 16)
    node.attributes = this.parseWithClause()
  this.semicolon()
}

while (!this.closes(tt.braceR, indent + (this.curLineStart <= continuedLine ? 1 : 0), line)) {
  if (this.isContextual("from")) break
  let elt = this.startNode()
  elt.local = this.parseModuleExportName()
  if (isDummy(elt.local)) break
  elt.exported = this.eatContextual("as") ? this.parseModuleExportName() : elt.local
  this.finishNode(elt, "ExportSpecifier")
  elts.push(elt)
  this.eat(tt.comma)
}

if (other) {
  let redefinition
  if (kind === "init") {
    redefinition = this.strict && other.init || other.get || other.set
  } else {
    redefinition = other.init || other[kind]
  }
  if (redefinition)
    this.raiseRecoverable(key.start, "Redefinition of property")
} else {
  other = propHash[name] = {
    init: false,
    get: false,
    set: false
  }
}

while (true) {
  let element = this.parseSubscript(base, startPos, startLoc, noCalls, maybeAsyncArrow, optionalChained, forInit)

  if (element.optional) optionalChained = true
  if (element === base || element.type === "ArrowFunctionExpression") {
    if (optionalChained) {
      const chainNode = this.startNodeAt(startPos, startLoc)
      chainNode.expression = element
      element = this.finishNode(chainNode, "ChainExpression")
    }
    return element
  }

  base = element
}

if (this.type === tt.invalidTemplate) {
  if (!isTagged) {
    this.raiseRecoverable(this.start, "Bad escape sequence in untagged template literal")
  }
  elem.value = {
    raw: this.value.replace(/\r\n?/g, "\n"),
    cooked: null
  }
} else {
  elem.value = {
    raw: this.input.slice(this.start, this.end).replace(/\r\n?/g, "\n"),
    cooked: this.value
  }
}

while (!this.eat(tt.braceR)) {
  if (!first) {
    this.expect(tt.comma)
    if (this.options.ecmaVersion >= 5 && this.afterTrailingComma(tt.braceR)) break
  } else first = false

  const prop = this.parseProperty(isPattern, refDestructuringErrors)
  if (!isPattern) this.checkPropClash(prop, propHash, refDestructuringErrors)
  node.properties.push(prop)
}

if (prop.value.params.length !== paramCount) {
  let start = prop.value.start
  if (prop.kind === "get")
    this.raiseRecoverable(start, "getter should have no params")
  else
    this.raiseRecoverable(start, "setter should have exactly one param")
} else {
  if (prop.kind === "set" && prop.value.params[0].type === "RestElement")
    this.raiseRecoverable(prop.value.params[0].start, "Setter cannot use rest params")
}

if (this.regexp_eatClassSetCharacter(state)) {
  const left = state.lastIntValue
  if (state.eat(0x2D /* - */) && this.regexp_eatClassSetCharacter(state)) {
    const right = state.lastIntValue
    if (left !== -1 && right !== -1 && left > right) {
      state.raise("Range out of order in character class")
    }
    return true
  }
  state.pos = start
}

if (usingKind) {
  let init = this.startNode()
  this.next()
  if (usingKind === "await using") {
    if (!this.canAwait) {
      this.raise(this.start, "Await using cannot appear outside of async function")
    }
    this.next()
  }
  this.parseVar(init, true, usingKind)
  this.finishNode(init, "VariableDeclaration")
  return this.parseForAfterInit(node, init, awaitAt)
}

if ((this.type === tt._in || (this.options.ecmaVersion >= 6 && this.isContextual("of"))) && init.declarations.length === 1) {
  if (this.type === tt._in) {
    if ((init.kind === "using" || init.kind === "await using") && !init.declarations[0].init) {
      this.raise(this.start, "Using declaration is not allowed in for-in loops")
    }
    if (this.options.ecmaVersion >= 9 && awaitAt > -1) this.unexpected(awaitAt)
  } else if (this.options.ecmaVersion >= 9) node.await = awaitAt > -1
  return this.parseForIn(node, init)
}

if (this.type === tt._catch) {
  let clause = this.startNode()
  this.next()
  if (this.eat(tt.parenL)) {
    clause.param = this.parseCatchClauseParam()
  } else {
    if (this.options.ecmaVersion < 10) this.unexpected()
    clause.param = null
    this.enterScope(0)
  }
  clause.body = this.parseBlock(false)
  this.exitScope()
  node.handler = this.finishNode(clause, "CatchClause")
}

while (this.type !== tt.braceR) {
  const element = this.parseClassElement(node.superClass !== null)
  if (element) {
    classBody.body.push(element)
    if (element.type === "MethodDefinition" && element.kind === "constructor") {
      if (hadConstructor) this.raiseRecoverable(element.start, "Duplicate constructor in the same class")
      hadConstructor = true
    } else if (element.key && element.key.type === "PrivateIdentifier" && isPrivateNameConflicted(privateNameMap, element)) {
      this.raiseRecoverable(element.key.start, `Identifier '#${element.key.name}' has already been declared`)
    }
  }
}

if (type === "Identifier")
    this.checkExport(exports, pat, pat.start)
  else if (type === "ObjectPattern")
    for (let prop of pat.properties)
      this.checkPatternExport(exports, prop)
  else if (type === "ArrayPattern")
    for (let elt of pat.elements) {
      if (elt) this.checkPatternExport(exports, elt)
    }
  else if (type === "Property")
    this.checkPatternExport(exports, pat.value)
  else if (type === "AssignmentPattern")
    this.checkPatternExport(exports, pat.left)
  else if (type === "RestElement")
    this.checkPatternExport(exports, pat.argument)

while (!this.eat(tt.braceR)) {
  if (!first) {
    this.expect(tt.comma)
    if (this.afterTrailingComma(tt.braceR)) break
  } else first = false

  const attr = this.parseImportAttribute()
  const keyName = attr.key.type === "Identifier" ? attr.key.name : attr.key.value
  if (hasOwn(attributeKeys, keyName))
    this.raiseRecoverable(attr.key.start, "Duplicate attribute key '" + keyName + "'")
  attributeKeys[keyName] = true
  nodes.push(attr)
}

for (;;) {
  if (this.pos >= this.input.length) this.raise(start, "Unterminated regular expression")
  let ch = this.input.charAt(this.pos)
  if (lineBreak.test(ch)) this.raise(start, "Unterminated regular expression")
  if (!escaped) {
    if (ch === "[") inClass = true
    else if (ch === "]" && inClass) inClass = false
    else if (ch === "/" && !inClass) break
    escaped = ch === "\\"
  } else escaped = false
  ++this.pos
}

if (
  utils.hasOwnProp(config2, 'validateStatus') &&
  utils.isUndefined(config2.validateStatus) &&
  getMergedTransitionalOption('validateStatusUndefinedResolves') === false
) {
  if (utils.hasOwnProp(config1, 'validateStatus')) {
    config.validateStatus = getMergedValue(undefined, config1.validateStatus);
  } else {
    delete config.validateStatus;
  }
}

if (!response.status || !validateStatus || validateStatus(response.status)) {
  resolve(response);
} else {
  reject(new AxiosError(
    'Request failed with status code ' + response.status,
    response.status >= 400 && response.status < 500 ? AxiosError.ERR_BAD_REQUEST : AxiosError.ERR_BAD_RESPONSE,
    response.config,
    response.request,
    response
  ));
}

for (const heritageClause of heritageClauses) {
	for (const { expression } of heritageClause.types) {
		if (expression.kind === ts.SyntaxKind.PropertyAccessExpression) {
			if (
				expression.expression.kind === ts.SyntaxKind.Identifier &&
				expression.expression.text === "Linter" &&
				expression.name.kind === ts.SyntaxKind.Identifier &&
				expression.name.text === "RulesRecord"
			) {
				return true;
			}
		}
	}
}

import { processLazyPreloader } from '../../shared/process-lazy-preloader.mjs';

export default function onLoad(e) {
  const swiper = this;
  if (swiper.destroyed) return;
  processLazyPreloader(swiper, e.target);
  if (
    swiper.params.cssMode ||
    (swiper.params.slidesPerView !== 'auto' && !swiper.params.autoHeight)
  ) {
    return;
  }
  swiper.update();
}

export default function unsetGrabCursor() {
  const swiper = this;
  if ((swiper.params.watchOverflow && swiper.isLocked) || swiper.params.cssMode) {
    return;
  }
  if (swiper.isElement) {
    swiper.__preventObserver__ = true;
  }
  swiper[swiper.params.touchEventsTarget === 'container' ? 'el' : 'wrapperEl'].style.cursor = '';
  if (swiper.isElement) {
    requestAnimationFrame(() => {
      swiper.__preventObserver__ = false;
    });
  }
}

import { createElement, getSlideTransformEl } from './utils.mjs';

export default function createShadow(suffix, slideEl, side) {
  const shadowClass = `swiper-slide-shadow${side ? `-${side}` : ''}${
    suffix ? ` swiper-slide-shadow-${suffix}` : ''
  }`;
  const shadowContainer = getSlideTransformEl(slideEl);
  let shadowEl = shadowContainer.querySelector(`.${shadowClass.split(' ').join('.')}`);

  if (!shadowEl) {
    shadowEl = createElement('div', shadowClass.split(' '));
    shadowContainer.append(shadowEl);
  }
  return shadowEl;
}

import { locEnd, locStart } from "../../location/index.js";
import { hasIgnorePragma, hasPragma } from "../../pragma.js";

function createParser(options) {
  options = typeof options === "function" ? { parse: options } : options;

  return {
    astFormat: "estree",
    hasPragma,
    hasIgnorePragma,
    locStart,
    locEnd,
    ...options,
  };
}
